const payment = require('../src/payment');

describe('Payment Processing', () => {
  let checkFundsSpy;

  beforeEach(() => {
    // Mock the external payment gateway
    checkFundsSpy = jest.spyOn(payment.paymentGateway, 'checkFunds');
  });

  afterEach(() => {
    checkFundsSpy.mockRestore();
  });

  test('should process valid credit card payment', async () => {
    // Mock successful funds check
    checkFundsSpy.mockResolvedValue(true);

    const result = await payment.processPayment({
      cardNumber: '4532015112830366',
      amount: 100.00,
      currency: 'USD'
    });

    expect(result.success).toBe(true);
    expect(result.transactionId).toBeDefined();
    expect(checkFundsSpy).toHaveBeenCalledWith('4532015112830366', 100.00);
  });

  test('should validate card number with Luhn algorithm', () => {
    // No mocking needed - testing pure validation logic
    expect(payment.validateCard('4532015112830366')).toBe(true);
    expect(payment.validateCard('4532015112830367')).toBe(false);
  });

  test('should reject card with insufficient funds', async () => {
    // Mock insufficient funds
    checkFundsSpy.mockResolvedValue(false);

    const result = await payment.processPayment({
      cardNumber: '4532015112830366',
      amount: 99999.00,
      currency: 'USD'
    });

