    expect(result.error).toBe('insufficient_funds');
    expect(checkFundsSpy).toHaveBeenCalledWith('4532015112830366', 99999.00);
  });

  test('should format currency correctly', () => {
    expect(payment.formatCurrency(100.5)).toBe('$100.50');
  });
});
